// ✅ Web Scraping — coleta preços de produto
async function scrapePrecos(url) {
  const browser = await puppeteer.launch({
    headless: 'new', // modo headless moderno
    args: ['--no-sandbox', '--disable-setuid-sandbox'],
  });

  const page = await browser.newPage();

  // Simula user-agent real para evitar bloqueio
  await page.setUserAgent(
    'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
  );

  await page.goto(url, { waitUntil: 'networkidle2' });

  // Aguarda elemento específico carregar
  await page.waitForSelector('.produto-preco', { timeout: 5000 });

  // Extrai dados do DOM
  const dados = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('.produto-card')).map(card => ({
      nome:  card.querySelector('.nome')?.innerText,
      preco: card.querySelector('.preco')?.innerText,
      disponivel: !card.querySelector('.esgotado'),
    }));
  });

  await browser.close();
  return dados;
}

