// ✅ Máquina de estados para chatbot
// Padrão robusto para gerenciar contexto de conversa

const ESTADOS = {
  INICIO:          'inicio',
  AGUARDANDO_CPF:  'aguardando_cpf',
  MENU_PRINCIPAL:  'menu_principal',
  RASTREANDO:      'rastreando',
  SUPORTE_HUMANO:  'suporte_humano',
};

// Armazenamento de sessão (Redis em produção)
const sessoes = new Map();

function obterSessao(telefone) {
  if (!sessoes.has(telefone)) {
    sessoes.set(telefone, {
      estado: ESTADOS.INICIO,
      dados:  {},
      historico: [],
    });
  }
  return sessoes.get(telefone);
}

async function processarMensagem(telefone, mensagem) {
  const sessao = obterSessao(telefone);
  sessao.historico.push({ role: 'user', content: mensagem, ts: Date.now() });

  let resposta = '';

  switch (sessao.estado) {

    case ESTADOS.INICIO:
      resposta = `Olá! Sou o assistente virtual.\n\nInforme seu CPF para continuar:`;
      sessao.estado = ESTADOS.AGUARDANDO_CPF;
      break;

    case ESTADOS.AGUARDANDO_CPF:
      const cpf = mensagem.replace(/\D/g, '');
      if (cpf.length !== 11) {
        resposta = '❌ CPF inválido. Informe apenas os 11 dígitos:';
        break;
      }
      sessao.dados.cpf   = cpf;
      sessao.dados.nome  = await buscarClientePorCPF(cpf);
      sessao.estado      = ESTADOS.MENU_PRINCIPAL;
      resposta = [
        `✅ Olá, ${sessao.dados.nome}!`,
        '',
        'Como posso ajudar?',
        '1️⃣ Rastrear pedido',
        '2️⃣ Cancelar pedido',
        '3️⃣ Falar com atendente',
      ].join('\n');
      break;

    case ESTADOS.MENU_PRINCIPAL:
      if (mensagem === '1' || mensagem.includes('rastrear')) {
        sessao.estado = ESTADOS.RASTREANDO;
        resposta = 'Informe o número do pedido:';
      } else if (mensagem === '3' || mensagem.includes('atendente')) {
        sessao.estado = ESTADOS.SUPORTE_HUMANO;
        resposta = '🔄 Transferindo para um atendente. Aguarde...';
        await notificarEquipe(telefone, sessao);
      }
      break;
  }

  sessao.historico.push({ role: 'bot', content: resposta, ts: Date.now() });
  return resposta;
}

