// ✅ Gerenciamento de carrinho (localStorage + API)
class Carrinho {
  constructor() {
    this.items = JSON.parse(localStorage.getItem('cart') || '[]');
  }

  adicionar(produto, quantidade = 1) {
    const existente = this.items.find(i => i.id === produto.id);
    if (existente) {
      existente.quantidade += quantidade;
    } else {
      this.items.push({ ...produto, quantidade });
    }
    this._salvar();
    return this;
  }

  remover(produtoId) {
    this.items = this.items.filter(i => i.id !== produtoId);
    this._salvar();
    return this;
  }

  get total() {
    return this.items.reduce((sum, i) => sum + (i.preco * i.quantidade), 0);
  }

  get quantidadeTotal() {
    return this.items.reduce((sum, i) => sum + i.quantidade, 0);
  }

  _salvar() {
    localStorage.setItem('cart', JSON.stringify(this.items));
  }
}

